def a(n):
    # Exhaustive fixed-point count on ladder L_n under closed-nbhd majority.
    # Top rail: 0..n-1, bottom rail: n..2n-1, rungs i <-> i+n.
    adj = {i: [] for i in range(2*n)}
    for i in range(n):
        if i < n - 1:
            adj[i] += [i+1]; adj[i+1] += [i]
            adj[i+n] += [i+n+1]; adj[i+n+1] += [i+n]
        adj[i] += [i+n]; adj[i+n] += [i]
    count = 0
    for m in range(1 << (2*n)):
        ok = True
        for v in range(2*n):
            s = ((m >> v) & 1) + sum((m >> u) & 1 for u in adj[v])
            size = 1 + len(adj[v])
            cur = (m >> v) & 1
            nxt = 1 if 2*s > size else (0 if 2*s < size else cur)
            if nxt != cur:
                ok = False; break
        if ok:
            count += 1
    return count
